import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"Character controller & follow camera","description":"","frontmatter":{},"headers":[],"relativePath":"guide/character-controller.md","filePath":"guide/character-controller.md","lastUpdated":1781972404000}'),i={name:"guide/character-controller.md"};function n(r,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="character-controller-follow-camera" tabindex="-1">Character controller &amp; follow camera <a class="header-anchor" href="#character-controller-follow-camera" aria-label="Permalink to &quot;Character controller &amp; follow camera&quot;">​</a></h1><p>The third-person controller (E1.1) is the core gameplay proof of the Phase 1 slice: a capsule character you walk, run, and jump around solid ground, tracked by a collision-aware follow camera. It lives in two engine-agnostic-at-the-core modules:</p><ul><li><a href="https://github.com/Flopsstuff/korovany/tree/main/src/game/controller" target="_blank" rel="noreferrer"><code>src/game/controller/</code></a> — capsule movement.</li><li><a href="https://github.com/Flopsstuff/korovany/tree/main/src/game/camera" target="_blank" rel="noreferrer"><code>src/game/camera/</code></a> — the third-person rig.</li></ul><p>Both follow the same split as the <a href="./input-system">input system</a>: a <strong>pure math core</strong> with no Babylon/DOM imports (unit-tested under the headless <code>NullEngine</code>), and a thin <strong>Babylon binding</strong> that wires the math to meshes, rays, and the camera.</p><h2 id="try-it" tabindex="-1">Try it <a class="header-anchor" href="#try-it" aria-label="Permalink to &quot;Try it&quot;">​</a></h2><p>The controller has a self-contained dev scene — open the app with the <code>?dev=controller</code> flag:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://korovany.aimost.pl/?dev=controller   # or http://localhost:5173/?dev=controller</span></span></code></pre></div><p>A flat ground with a few pillars, the capsule (the hero GLB mounts on it), and the follow camera. <strong>Click the canvas</strong> to capture the pointer for mouse-look.</p><h2 id="controls" tabindex="-1">Controls <a class="header-anchor" href="#controls" aria-label="Permalink to &quot;Controls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Key</th></tr></thead><tbody><tr><td>Move</td><td><strong>W A S D</strong></td></tr><tr><td>Sprint</td><td>hold <strong>Shift</strong></td></tr><tr><td>Jump</td><td><strong>Space</strong></td></tr><tr><td>Look</td><td>mouse (after clicking to lock the pointer)</td></tr></tbody></table><p>Keys come from the data-driven <a href="./input-system#bindings">input bindings</a>, so they are rebindable; the table above is the default map. Movement is <strong>camera-relative</strong> — &quot;forward&quot; is always away from the camera — and diagonals are normalised so they are not faster than cardinal movement.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><h3 id="movement-controller-movement-ts" tabindex="-1">Movement (<code>controller/movement.ts</code>) <a class="header-anchor" href="#movement-controller-movement-ts" aria-label="Permalink to &quot;Movement (`controller/movement.ts`)&quot;">​</a></h3><p><code>stepMovement(state, input, groundHeight, params, dt)</code> advances one fixed step of the pure simulation. Each step, in order:</p><ol><li><strong>Horizontal</strong> — move by <code>speed · dt</code> along the world-space direction the binding resolved (walk or sprint speed).</li><li><strong>Jump</strong> — on the <em>rising edge</em> of the jump input, if allowed (see below), set the upward jump velocity.</li><li><strong>Gravity</strong> — integrate <code>velY -= gravity · dt</code>, then <code>posY += velY · dt</code>.</li><li><strong>Ground clamp</strong> — if the feet would sink at or below the ground while descending, snap the capsule origin to <code>groundHeight + capsuleHalfHeight</code> and zero the vertical velocity. Clamping only when descending keeps a jump arc from being cut short by the ground it just left.</li><li><strong>Coyote bookkeeping</strong> — refill the grace window while grounded, otherwise count it down.</li></ol><p>The capsule&#39;s origin is its centre (matching Babylon&#39;s <code>CreateCapsule</code>), so the feet rest on ground <code>g</code> when the origin sits at <code>g + capsuleHalfHeight</code>.</p><h4 id="jump-coyote-time-and-no-double-jump" tabindex="-1">Jump, coyote-time, and no double-jump <a class="header-anchor" href="#jump-coyote-time-and-no-double-jump" aria-label="Permalink to &quot;Jump, coyote-time, and no double-jump&quot;">​</a></h4><ul><li><strong>Coyote-time</strong> (<code>coyoteTime</code>, default <code>0.12 s</code>): a short grace window after walking off a ledge during which a jump is still allowed. It makes ledge jumps feel responsive instead of dropping inputs a frame late.</li><li><strong>No double-jump</strong>: a separate <code>canJump</code> guard is consumed by a jump and only refilled on landing, so a second jump is impossible in mid-air — even within the coyote window.</li><li>Jump is <strong>edge-triggered</strong>: holding the key does not auto-bunny-hop; you must release and press again.</li></ul><h3 id="tuning-movementparams" tabindex="-1">Tuning (<code>MovementParams</code>) <a class="header-anchor" href="#tuning-movementparams" aria-label="Permalink to &quot;Tuning (`MovementParams`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Param</th><th>Default</th><th>Meaning</th></tr></thead><tbody><tr><td><code>walkSpeed</code></td><td><code>4</code></td><td>Ground speed, units/s.</td></tr><tr><td><code>sprintSpeed</code></td><td><code>7</code></td><td>Speed while Shift is held, units/s.</td></tr><tr><td><code>gravity</code></td><td><code>24</code></td><td>Downward acceleration, units/s².</td></tr><tr><td><code>jumpSpeed</code></td><td><code>8</code></td><td>Initial upward velocity of a jump, units/s.</td></tr><tr><td><code>coyoteTime</code></td><td><code>0.12</code></td><td>Grace window after leaving ground, seconds.</td></tr><tr><td><code>capsuleHalfHeight</code></td><td><code>0.9</code></td><td>Origin-to-feet distance (half the capsule height).</td></tr></tbody></table><p>The <code>CharacterController</code> binding keeps <code>capsuleHalfHeight</code> in lock-step with the actual capsule mesh height so the feet always rest exactly on the ground.</p><h3 id="ground-collision" tabindex="-1">Ground collision <a class="header-anchor" href="#ground-collision" aria-label="Permalink to &quot;Ground collision&quot;">​</a></h3><p>The binding casts a short ray straight down from the capsule origin (<code>capsuleHalfHeight + groundProbe</code>, default probe <code>0.4</code>) and treats the picked point&#39;s <code>Y</code> as the ground height — Babylon&#39;s built-in <code>pickWithRay</code>, no bespoke physics engine. Out of reach → <code>null</code> → the capsule falls freely. The probe must exceed one step of fall to avoid tunnelling at speed.</p><h3 id="follow-camera-camera" tabindex="-1">Follow camera (<code>camera/</code>) <a class="header-anchor" href="#follow-camera-camera" aria-label="Permalink to &quot;Follow camera (`camera/`)&quot;">​</a></h3><p>The rig wraps Babylon&#39;s built-in <code>ArcRotateCamera</code> (boring-tech lens — orbit, zoom, and target tracking are solved) and adds two things:</p><ul><li><strong>Mouse-look</strong> driven by the input system&#39;s accumulated <code>lookDX/lookDY</code> rather than <code>attachControl</code>, so look obeys the same intent pipeline as movement and stays pointer-lock friendly. Pitch is clamped to <code>[minPitch, maxPitch]</code> so the camera never flips over the top or sinks through the floor.</li><li>A <strong>collision-aware boom</strong>: each frame a ray from the player toward the ideal camera spot pulls the radius in to <code>hitDistance − collisionMargin</code> when geometry would otherwise clip between the camera and the player. The boom never extends past the desired distance and never goes negative.</li></ul><p>The rig follows the player by locking the camera&#39;s target to the capsule mesh, so it tracks automatically as the controller moves.</p><h4 id="camera-tuning-cameraparams" tabindex="-1">Camera tuning (<code>CameraParams</code>) <a class="header-anchor" href="#camera-tuning-cameraparams" aria-label="Permalink to &quot;Camera tuning (`CameraParams`)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Param</th><th>Default</th><th>Meaning</th></tr></thead><tbody><tr><td><code>yawSensitivity</code> / <code>pitchSensitivity</code></td><td><code>0.0035</code></td><td>Radians of orbit per pixel of mouse movement.</td></tr><tr><td><code>minPitch</code> / <code>maxPitch</code></td><td><code>0.35</code> / <code>1.45</code></td><td>Pitch clamp (radians from +Y).</td></tr><tr><td><code>distance</code></td><td><code>6</code></td><td>Desired boom length, units.</td></tr><tr><td><code>collisionMargin</code></td><td><code>0.3</code></td><td>Gap kept in front of an occluder the boom pulls in to.</td></tr></tbody></table><h2 id="running-under-the-loop" tabindex="-1">Running under the loop <a class="header-anchor" href="#running-under-the-loop" aria-label="Permalink to &quot;Running under the loop&quot;">​</a></h2><p>The <code>CharacterController</code> is a loop <a href="./game-loop#adding-a-system"><code>System</code></a>: register it with the fixed-step scheduler and it advances once per fixed step, so movement stays framerate-independent. The host samples input once per render frame, holds that intent for the frame&#39;s sub-steps, then updates the camera once the controller has moved the player:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> controller</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CharacterController</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ scene, camera: rig.camera, getIntent })</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">loop.scheduler.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">register</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(controller)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">engine.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">runRenderLoop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  frameIntent </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> input.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sample</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()                 </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// once per frame; clears look delta</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  loop.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">advance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(engine.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getDeltaTime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// runs controller sub-steps</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  rig.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(frameIntent.lookDX, frameIntent.lookDY) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// look + boom, after the move</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  scene.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">render</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>See <a href="https://github.com/Flopsstuff/korovany/tree/main/src/scenes/controllerPlayground.ts" target="_blank" rel="noreferrer"><code>src/scenes/controllerPlayground.ts</code></a> for the full dev-scene wiring.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li><code>controller/movement.test.ts</code> — pure gravity, ground clamp, jump, coyote-time window, and the no-double-jump rule.</li><li><code>camera/boom.test.ts</code> — pure look clamp and boom pull-in.</li><li><code>controller/characterController.test.ts</code> — the Babylon bindings under <code>NullEngine</code>: real downward-ray ground landing, camera-relative walking, jumping, running as a scheduler system, and the camera boom against a real occluder.</li></ul>',35)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
